            aOrbiterB = ((aWandererE + RotL64(aScatter, 21U)) + 0xEF16E9B2D32423F9ULL) + aPhaseDOrbiterAssignSaltF[(((31U - aIndex) + 11U)) & S_SALT1];
            aOrbiterE = (aWandererG + RotL64(aIngress, 38U)) + 0x18E1A4E10ECC9F5AULL;
            aOrbiterJ = (((aWandererC + RotL64(aScatter, 53U)) + RotL64(aCarry, 37U)) + 0x4A6216F9253F6526ULL) + aPhaseDOrbiterAssignSaltB[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterF = ((aWandererI + RotL64(aCross, 13U)) + RotL64(aCarry, 3U)) + 0x4C645969A61CB490ULL;
            //
