            aOrbiterB = RotL64((aOrbiterB * 0x6B63A6C5B43D3B4DULL), 3U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterJ) + 0x9B05045486618AF3ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterB) ^ 0x75D5F37285BDECB7ULL;
            aOrbiterG = RotL64((aOrbiterG * 0xD6C279284DD51A0FULL), 53U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterF) + 0xA49F9FDD08FDFBAEULL) + aPhaseDOrbiterUpdateSaltF[((aIndex + 13U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterJ) ^ 0x5A1F660BDD2F09E7ULL;
            aOrbiterC = RotL64((aOrbiterC * 0x52154488CCE78443ULL), 47U);
