            //
            aOrbiterG = (aWandererB + RotL64(aScatter, 20U)) + 0x4616CCEA512AACA8ULL;
            aOrbiterF = (((aWandererE + RotL64(aPrevious, 35U)) + RotL64(aCarry, 23U)) + 0xC87CA37BB42C35EFULL) + aPhaseCOrbiterAssignSaltB[(((31U - aIndex) + 8U)) & S_SALT1];
            aOrbiterB = ((aWandererF + RotL64(aCross, 5U)) + RotL64(aCarry, 39U)) + 0x232593B616ED973EULL;
            aOrbiterJ = (aWandererA + RotL64(aIngress, 11U)) + 0x21C75397837D35E5ULL;
            aOrbiterD = ((aWandererK + RotL64(aPrevious, 51U)) + 0x8816B96A99350384ULL) + aPhaseCOrbiterAssignSaltA[(((31U - aIndex) + 6U)) & S_SALT1];
            aOrbiterI = ((aWandererG + RotL64(aIngress, 27U)) + RotL64(aCarry, 51U)) + 0x3DE8E7D5C347B4DDULL;
            aOrbiterH = (aWandererC + RotL64(aScatter, 43U)) + 0xA44CE9EEE31573ADULL;
            //
            aOrbiterG = ((aOrbiterG + aOrbiterF) + 0x420815656354FDFDULL) + aPhaseCOrbiterUpdateSaltE[((aIndex + 26U)) & S_SALT1];
            aOrbiterB = ((aOrbiterB ^ aOrbiterG) ^ 0x450898365EDEB637ULL) ^ aPhaseCOrbiterUpdateSaltA[((aIndex + 11U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 0xF3D44358D655748DULL), 47U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterJ) + 0x0F644CC2CF4C5C25ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterF) ^ 0x80C407AAFE7DA133ULL;
