            aOrbiterD = (aOrbiterD + aOrbiterH) + 0xEDEC5FA217A42123ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterD) ^ 0xB0306EB8FD9DCF3AULL;
            aOrbiterG = RotL64((aOrbiterG * 0xE71EE9D313226553ULL), 35U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 0xE2E6EF13CB273160ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterB) ^ 0x381E391E62E69D98ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x15B7602DF7CAAB3DULL), 57U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterI) + 0x7E6A58E4C52C34CBULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterH) ^ 0xDE444331E87BB34DULL;
            aOrbiterF = RotL64((aOrbiterF * 0x343D6A2D9AA5D3DFULL), 13U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterB) + 0x1A1BF2445C13E07DULL;
            aOrbiterH = ((aOrbiterH ^ aOrbiterJ) ^ 0x98C79ADFA4AD20E0ULL) ^ aPhaseCOrbiterUpdateSaltC[(((31U - aIndex) + 7U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 0x4813A6F7855733CFULL), 21U);
            //
            aIngress = RotL64(aOrbiterI, 4U) ^ aOrbiterF;
            aIngress = aIngress + (aOrbiterJ ^ RotL64(aOrbiterD, 23U));
            aIngress = aIngress + (aOrbiterG ^ RotL64(aOrbiterH, 11U));
