            aIngress = TwistMix64::DiffuseC((aIngress + aScatter));
            //
            aWandererG = aWandererG ^ ((RotL64(aCross, 47U) + RotL64(aOrbiterH, 37U)) + aOrbiterI);
            aWandererF = aWandererF + ((((RotL64(aScatter, 21U) + RotL64(aOrbiterG, 5U)) + aOrbiterD) + RotL64(aCarry, 53U)) + aPhaseCWandererUpdateSaltF[((aIndex + 17U)) & S_SALT1]);
            aWandererE = aWandererE ^ ((RotL64(aPrevious, 58U) + RotL64(aOrbiterF, 27U)) + aOrbiterD);
            aWandererA = aWandererA + ((((RotL64(aIngress, 11U) + aOrbiterG) + RotL64(aOrbiterI, 51U)) + RotL64(aCarry, 29U)) + aPhaseCWandererUpdateSaltD[((aIndex + 21U)) & S_SALT1]);
            aWandererC = aWandererC ^ ((RotL64(aCross, 27U) + RotL64(aOrbiterD, 60U)) + aOrbiterB);
