            aIngress ^= (RotL64(aWindLaneC[((aIndex + 1924U)) & S_BLOCK1], 21U) ^ RotL64(aFireLaneA[((S_BLOCK1 - aIndex + 243U)) & S_BLOCK1], 29U));
            aIngress = TwistMix64::DiffuseC(aIngress);
